package com.chaobo.scm.supplier.application.asn;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.domain.asn.AsnRepository;import com.chaobo.scm.supplier.infrastructure.persistence.asn.AsnTransportTrailQueryMapper;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.OffsetDateTime;import java.util.*;
@Service public class AsnTransportQueryApplicationService {private final AsnRepository asns;private final AsnTransportTrailQueryMapper mapper;public AsnTransportQueryApplicationService(AsnRepository asns,AsnTransportTrailQueryMapper mapper){this.asns=asns;this.mapper=mapper;}@Transactional(readOnly=true)public List<Trail> trails(long asnId,Long scope){var asn=asns.findById(asnId).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"ASN不存在"));if(scope!=null&&scope!=asn.supplierId())throw new BusinessException(ErrorCode.NOT_FOUND,"ASN不存在");return mapper.list(asnId).stream().map(r->new Trail(r.shipmentId(),r.waybillNo(),r.status(),r.node(),r.occurredAt(),r.exceptionCode(),r.exceptionReason(),r.sourceVersion())).toList();}public record Trail(Long shipmentId,String waybillNo,int transportStatus,String trackNode,OffsetDateTime occurredAt,String exceptionCode,String exceptionReason,long sourceVersion){}}
